# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import requests

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    
    # Extract headers
    headers = request['headers']
    
    # Check for 'X-Enrich-URL' header
    enrich_url = headers.get('x-enrich-url')
    if enrich_url:
        enrich_url_value = enrich_url[0]['value']
        
        # Fetch additional data from the specified URL
        try:
            response = requests.get(enrich_url_value)
            if response.status_code == 200:
                context_data = response.json()
                # Add or modify headers with context data if needed
                request['headers']['x-context-data'] = [{'key': 'X-Context-Data', 'value': json.dumps(context_data)}]
        except requests.RequestException as e:
            # Handle request failures or errors
            request['headers']['x-context-error'] = [{'key': 'X-Context-Error', 'value': str(e)}]
    
    return request